import { useState, useCallback, useMemo, useRef, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { usePersistentState } from './usePersistentState';
import { SavedReport, SearchFilters, SavingReportState, MatchResult, SpreadsheetData } from '../types';

const DEFAULT_SEARCH_FILTERS: SearchFilters = {
    dateRange: { start: null, end: null },
    valueFilter: { operator: 'any', value1: null, value2: null },
    transactionType: 'all',
    reconciliationStatus: 'all',
    filterBy: 'none',
    churchIds: [],
    contributorName: '',
    reportId: null,
};

const MAX_REPORTS_PER_USER = 60;

export const useReportManager = (user: any | null, showToast: (msg: string, type: 'success' | 'error') => void) => {

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [savedReports, setSavedReports] = useState<SavedReport[]>([]);
    const [searchFilters, setSearchFilters] = usePersistentState<SearchFilters>(`identificapix-search-filters${userSuffix}`, DEFAULT_SEARCH_FILTERS);
    const [isSearchFiltersOpen, setIsSearchFiltersOpen] = useState(false);
    const [savingReportState, setSavingReportState] = useState<SavingReportState | null>(null);

    // Ref para evitar loops de salvamento repetidos com o mesmo dado
    const lastSavedPayloadRef = useRef<string>('');

    /**
     * 📥 CARGA INICIAL (REIDRATAÇÃO DO BACKEND)
     * Garante que ao recarregar a página, a lista de relatórios (e planilhas vinculadas) seja recuperada.
     */
    useEffect(() => {
        if (!user) {
            setSavedReports([]);
            return;
        }

        const fetchReports = async () => {
            try {
                const { data, error } = await supabase
                    .from('saved_reports')
                    .select('*')
                    .eq('user_id', user.id)
                    .order('created_at', { ascending: false });

                if (error) throw error;

                if (data) {
                    const hydrated: SavedReport[] = data.map(r => ({
                        id: r.id,
                        name: r.name,
                        createdAt: r.created_at,
                        recordCount: r.record_count,
                        user_id: r.user_id,
                        data: typeof r.data === 'string' ? JSON.parse(r.data) : r.data
                    }));
                    setSavedReports(hydrated);
                }
            } catch (err) {
                console.error("[ReportManager] Erro ao carregar relatórios históricos:", err);
            }
        };

        fetchReports();
    }, [user]);

    const openSearchFilters = useCallback(() => setIsSearchFiltersOpen(true), []);
    const closeSearchFilters = useCallback(() => setIsSearchFiltersOpen(false), []);
    const clearSearchFilters = useCallback(() => setSearchFilters(DEFAULT_SEARCH_FILTERS), [setSearchFilters]);

    const updateSavedReportName = useCallback(async (reportId: string, newName: string) => {
        if(!user) return;
        setSavedReports(prev => prev.map(r => r.id === reportId ? { ...r, name: newName } : r));
        const { error } = await supabase.from('saved_reports').update({ name: newName }).eq('id', reportId);
        if (error) showToast('Erro ao renomear relatório.', 'error');
        else showToast('Relatório renomeado.', 'success');
    }, [user, showToast]);

    /**
     * 🔐 PERSISTÊNCIA MESTRE (UPSERT COM MERGE)
     * Salva as alterações de uma planilha ou conciliação sem apagar os dados existentes do outro tipo.
     */
    const overwriteSavedReport = useCallback(async (reportId: string, results: MatchResult[], spreadsheetData?: SpreadsheetData) => {
        if (!user || !reportId) return;

        // Busca o estado atual local para merge (evita perda de dados em atualizações parciais)
        const existingReport = savedReports.find(r => r.id === reportId);
        const currentData = existingReport?.data || { results: [], sourceFiles: [], bankStatementFile: null };

        // Bloqueio de salvamento vazio: só impede se AMBOS forem inexistentes
        if ((!results || results.length === 0) && !spreadsheetData && !currentData.results && !currentData.spreadsheet) return;

        // Dedup: Evita salvar exatamente o mesmo dado que já foi enviado
        const currentPayload = JSON.stringify({ r: results?.length || 0, s: !!spreadsheetData });
        if (lastSavedPayloadRef.current === currentPayload + reportId) return;
        lastSavedPayloadRef.current = currentPayload + reportId;

        // Lógica de Merge: Preserva o que já existe se o novo for omitido
        const mergedData = {
            ...currentData,
            results: (results && results.length > 0) ? results : currentData.results,
            spreadsheet: spreadsheetData || currentData.spreadsheet
        };

        const recordCount = spreadsheetData?.rows ? spreadsheetData.rows.length : (mergedData.results?.length || 0);

        // Atualiza estado local de forma otimista
        setSavedReports(prev => prev.map(r => r.id === reportId ? {
            ...r,
            recordCount,
            data: mergedData
        } : r));

        // Persistência Cloud
        const { error } = await supabase
            .from('saved_reports')
            .update({ 
                data: mergedData as any,
                record_count: recordCount 
            })
            .eq('id', reportId);

        if (error) {
            console.error("[AutoSave] Erro ao persistir no Supabase:", error);
            showToast("Falha ao salvar alterações no servidor.", "error");
        } else {
            showToast("Alterações salvas no servidor.", "success");
        }
    }, [user, showToast, savedReports]);

    const saveFilteredReport = useCallback((results: MatchResult[]) => {
        setSavingReportState({
            type: 'search',
            results: results,
            groupName: 'Filtrado'
        });
    }, []);

    const openSaveReportModal = useCallback((state: SavingReportState) => setSavingReportState(state), []);
    const closeSaveReportModal = useCallback(() => setSavingReportState(null), []);

    /**
     * CRIA NOVO REGISTRO
     * Retorna o ID gerado para que o controlador possa marcar como "Relatório Ativo".
     */
    const confirmSaveReport = useCallback(async (name: string): Promise<string | null> => {
        if (!savingReportState || !user) return null;

        if (savedReports.length >= MAX_REPORTS_PER_USER) {
            showToast(`Limite de ${MAX_REPORTS_PER_USER} relatórios atingido.`, 'error');
            closeSaveReportModal();
            return null;
        }

        const isSpreadsheet = savingReportState.type === 'spreadsheet';
        const recordCount = isSpreadsheet && savingReportState.spreadsheetData?.rows
            ? savingReportState.spreadsheetData.rows.length 
            : savingReportState.results.length;

        const newReportId = `rep-${Date.now()}`;
        const newReport: SavedReport = {
            id: newReportId,
            name: name,
            createdAt: new Date().toISOString(),
            recordCount: recordCount,
            user_id: user.id,
            data: {
                results: savingReportState.results || [],
                sourceFiles: [],
                bankStatementFile: null,
                spreadsheet: isSpreadsheet ? savingReportState.spreadsheetData : undefined
            }
        };

        setSavedReports(prev => [newReport, ...prev]);
        closeSaveReportModal();

        const { error } = await supabase.from('saved_reports').insert({
            id: newReport.id,
            name: newReport.name,
            record_count: newReport.recordCount,
            user_id: newReport.user_id,
            data: newReport.data as any
        });

        if (error) {
            setSavedReports(prev => prev.filter(r => r.id !== newReport.id));
            showToast('Erro ao salvar relatório.', 'error');
            return null;
        } else {
            showToast('Relatório criado!', 'success');
            return newReportId;
        }
    }, [savingReportState, user, showToast, closeSaveReportModal, savedReports.length]);

    const deleteOldReports = useCallback(async (dateThreshold: Date) => {
        if (!user) return;
        const reportsToDelete = savedReports.filter(r => new Date(r.createdAt) < dateThreshold);
        if (reportsToDelete.length === 0) return;
        setSavedReports(prev => prev.filter(r => new Date(r.createdAt) >= dateThreshold));
        await supabase.from('saved_reports').delete().lt('created_at', dateThreshold.toISOString()).eq('user_id', user.id);
        showToast(`${reportsToDelete.length} itens removidos.`, "success");
    }, [user, savedReports, showToast]);

    const allHistoricalResults = useMemo(() => {
        return savedReports
            .filter(r => r.data && r.data.results)
            .flatMap(report => report.data!.results);
    }, [savedReports]);

    return useMemo(() => ({
        savedReports, setSavedReports,
        maxSavedReports: MAX_REPORTS_PER_USER,
        searchFilters, setSearchFilters,
        isSearchFiltersOpen, openSearchFilters, closeSearchFilters, clearSearchFilters,
        savingReportState, openSaveReportModal, closeSaveReportModal, confirmSaveReport,
        updateSavedReportName, saveFilteredReport, overwriteSavedReport,
        deleteOldReports,
        allHistoricalResults
    }), [
        savedReports, searchFilters, isSearchFiltersOpen, savingReportState, allHistoricalResults,
        setSavedReports, setSearchFilters, openSearchFilters, closeSearchFilters, clearSearchFilters,
        openSaveReportModal, closeSaveReportModal, confirmSaveReport, updateSavedReportName, saveFilteredReport, overwriteSavedReport,
        deleteOldReports
    ]);
};

import { MatchResult, Transaction } from '../types';
import React, { createContext, useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { useReconciliationActions } from '../hooks/useReconciliationActions';
import { useModalController } from '../hooks/useModalController';
import { useDataDeletion } from '../hooks/useDataDeletion';
import { useAiAutoIdentify } from '../hooks/useAiAutoIdentify';
import { useSummaryData } from '../hooks/useSummaryData';
import { supabase } from '../services/supabaseClient';
import { PLACEHOLDER_CHURCH } from '../services/processingService';

export const AppContext = createContext<any>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const { showToast, setIsLoading, setActiveView } = useUI();
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);

    const modalController = useModalController();
    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const effectiveIgnoreKeywords = useMemo(() => {
        return referenceData.customIgnoreKeywords || [];
    }, [referenceData.customIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user, churches: referenceData.churches, banks: referenceData.banks,
        fileModels: referenceData.fileModels, fetchModels: referenceData.fetchModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance, customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords, learnedAssociations: referenceData.learnedAssociations,
        showToast, setIsLoading, setActiveView
    });

    /**
     * 👁️ VISUALIZADOR DE RELATÓRIOS
     * Carrega os dados de um relatório salvo e redireciona para a tela correta.
     */
    const viewSavedReport = useCallback(async (reportId: string) => {
        const report = reportManager.savedReports.find(r => r.id === reportId);
        if (!report) return;

        setIsLoading(true);
        try {
            let results = report.data?.results;
            let spreadsheet = report.data?.spreadsheet;

            if (!results && !spreadsheet) {
                const { data, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;
                const parsedData = typeof data?.data === 'string' ? JSON.parse(data.data) : data?.data;
                results = parsedData?.results;
                spreadsheet = parsedData?.spreadsheet;
            }

            if ((results && results.length > 0) || spreadsheet) {
                reconciliation.setActiveReportId(reportId);
                reconciliation.setHasActiveSession(true);

                // Se tiver resultados de conciliação, carrega na lista viva e vai para Relatórios
                if (results && results.length > 0) {
                    const hydrated = results.map((r: any) => ({
                        ...r,
                        church: referenceData.churches.find((c: any) => c.id === (r.church?.id || r._churchId)) || r.church || PLACEHOLDER_CHURCH
                    }));
                    reconciliation.setMatchResults(hydrated);
                    setActiveView('reports');
                } 
                // Se for apenas planilha ou ranking sem resultados brutos, vai para o Gerador
                else if (spreadsheet) {
                    setActiveView('smart_analysis');
                }

                showToast(`Relatório "${report.name}" carregado.`, "success");
            } else {
                showToast("Este relatório está vazio.", "error");
            }
        } catch (error: any) {
            console.error("[AppContext] Erro ao abrir relatório:", error);
            showToast("Erro ao carregar os dados do relatório.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, referenceData.churches, reconciliation, setActiveView, setIsLoading, showToast]);

    /**
     * 🔐 PERSISTÊNCIA MESTRE (Auto-Save Direto)
     * Salva o estado ATUAL e COMPLETO de matchResults no banco de dados.
     */
    const persistActiveReport = useCallback(async (customResults?: MatchResult[]) => {
        const reportId = reconciliation.activeReportId;
        const resultsToSave = customResults || reconciliation.matchResults;

        if (reportId && (resultsToSave.length > 0 || reportManager.savedReports.find(r => r.id === reportId)?.data?.spreadsheet)) {
            setIsSyncing(true);
            try {
                await reportManager.overwriteSavedReport(reportId, resultsToSave);
            } finally {
                setTimeout(() => setIsSyncing(false), 500);
            }
        }
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager]);

    /**
     * 📝 WRAPPER DE CRIAÇÃO
     * Estende o confirmSaveReport para atualizar o activeReportId no reconciliation state.
     */
    const wrappedConfirmSaveReport = useCallback(async (name: string) => {
        const newId = await reportManager.confirmSaveReport(name);
        if (newId) {
            reconciliation.setActiveReportId(newId);
            reconciliation.setHasActiveSession(true);
        }
    }, [reportManager, reconciliation]);

    const reconciliationActions = useReconciliationActions({ 
        reconciliation, 
        referenceData, 
        showToast,
        onAfterAction: persistActiveReport 
    });

    const { confirmDeletion } = useDataDeletion({ user, modalController, referenceData, reportManager, reconciliation, showToast });
    const { runAiAutoIdentification } = useAiAutoIdentify({ 
        reconciliation, 
        referenceData, 
        effectiveIgnoreKeywords, 
        setIsLoading, 
        showToast,
        onAfterIdentification: persistActiveReport 
    });

    const summary = useSummaryData(reconciliation, reportManager);

    const saveSmartEdit = useCallback(async (result: MatchResult) => {
        if (result.status === 'IDENTIFICADO' && result.contributor && result.church) {
             referenceData.learnAssociation(result);
        }

        const updatedSet = reconciliation.matchResults.map((r: any) => 
            r.transaction.id === result.transaction.id ? result : r
        );

        reconciliation.setMatchResults(updatedSet);
        modalController.closeSmartEdit();
        showToast("Identificação atualizada.", "success");

        if (reconciliation.activeReportId) {
            persistActiveReport(updatedSet);
        }
    }, [reconciliation, referenceData, modalController, showToast, persistActiveReport]);

    const openManualIdentify = useCallback((txId: string) => {
        const tx = reconciliation.matchResults.find((r: any) => r.transaction.id === txId)?.transaction;
        if (tx) reconciliation.setManualIdentificationTx(tx);
    }, [reconciliation]);

    const handleGmailSyncSuccess = useCallback((transactions: Transaction[]) => {
        reconciliation.importGmailTransactions(transactions);
        setTimeout(() => reconciliation.handleCompare(), 500);
    }, [reconciliation]);

    const activeSpreadsheetData = useMemo(() => {
        if (!reconciliation.activeReportId) return undefined;
        const report = reportManager.savedReports.find(r => r.id === reconciliation.activeReportId);
        return report?.data?.spreadsheet;
    }, [reconciliation.activeReportId, reportManager.savedReports]);

    useEffect(() => { if (user !== undefined) setInitialDataLoaded(true); }, [user]);

    const value = useMemo(() => ({
        ...referenceData, 
        effectiveIgnoreKeywords, 
        ...reportManager, 
        confirmSaveReport: wrappedConfirmSaveReport, // Override with wrapped version
        ...reconciliation,
        ...reconciliationActions, 
        ...modalController,
        initialDataLoaded, summary, activeSpreadsheetData, saveSmartEdit, isSyncing,
        saveCurrentReportChanges: persistActiveReport,
        handleGmailSyncSuccess, confirmDeletion, openManualIdentify, runAiAutoIdentification,
        findMatchResult: reconciliation.findMatchResult,
        loadingAiId: reconciliation.loadingAiId,
        viewSavedReport
    }), [
        referenceData, effectiveIgnoreKeywords, reportManager, wrappedConfirmSaveReport, reconciliation, reconciliationActions,
        modalController, initialDataLoaded, summary, activeSpreadsheetData, 
        saveSmartEdit, isSyncing, persistActiveReport, handleGmailSyncSuccess, confirmDeletion, openManualIdentify,
        runAiAutoIdentification, viewSavedReport
    ]);

    return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
};

import React, { useState, useContext, useCallback, useMemo, useEffect, useRef } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { supabase } from '../services/supabaseClient';
import { MatchResult, SpreadsheetData, ManualRow, ColumnDef } from '../types';
import { analysisProcessor, SortConfig } from '../services/analysisProcessor';
import { rankingService } from '../services/rankingService';
import { PLACEHOLDER_CHURCH, groupResultsByChurch } from '../services/processingService';

export const useSmartAnalysisController = () => {
    const { t } = useTranslation();
    const { 
        matchResults, setMatchResults, setReportPreviewData, setHasActiveSession,
        savedReports, openSaveReportModal, activeSpreadsheetData, activeReportId,
        setActiveReportId, overwriteSavedReport, churches 
    } = useContext(AppContext);
    const { showToast, setIsLoading } = useUI();

    const [activeTemplate, setActiveTemplate] = useState<'ranking' | 'manual_structure'>('ranking');
    const [reportTitle, setReportTitle] = useState('Relatório Financeiro');
    const [reportLogo, setReportLogo] = useState<string | null>(null);
    const [signatures, setSignatures] = useState<string[]>(['Tesoureiro', 'Pastor Responsável']);
    const [manualRows, setManualRows] = useState<ManualRow[]>([]);
    const [isRankingLoading, setIsRankingLoading] = useState(false);
    const [columns, setColumns] = useState<ColumnDef[]>(analysisProcessor.createDefaultColumns());
    const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);
    const [sumModal, setSumModal] = useState<{ isOpen: boolean, rowId: string, colId: string, currentValue: number } | null>(null);
    const [sumValue, setSumValue] = useState('');
    const [showReportSelector, setShowReportSelector] = useState(false);

    // Estados para controle de alterações (Dirty State)
    const [isDirty, setIsDirty] = useState(false);
    const lastSavedData = useRef<string>('');
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Função utilitária para capturar o estado atual da planilha em string
    const getSnapshot = useCallback(() => {
        return JSON.stringify({
            title: reportTitle,
            logo: reportLogo,
            cols: columns,
            rows: manualRows,
            sigs: signatures
        });
    }, [reportTitle, reportLogo, columns, manualRows, signatures]);

    // Efeito para carregar dados de um relatório salvo (Reidratação REAL)
    useEffect(() => {
        if (activeSpreadsheetData && activeReportId) {
            setManualRows(activeSpreadsheetData.rows || []);
            setColumns(activeSpreadsheetData.columns || analysisProcessor.createDefaultColumns());
            setReportTitle(activeSpreadsheetData.title || 'Relatório Financeiro');
            setSignatures(activeSpreadsheetData.signatures || ['Tesoureiro', 'Pastor Responsável']);
            setReportLogo(activeSpreadsheetData.logo || null);
            setActiveTemplate('manual_structure');

            // Define o ponto de referência para detecção de alterações
            lastSavedData.current = JSON.stringify({
                title: activeSpreadsheetData.title,
                logo: activeSpreadsheetData.logo,
                cols: activeSpreadsheetData.columns,
                rows: activeSpreadsheetData.rows,
                sigs: activeSpreadsheetData.signatures || []
            });
            setIsDirty(false);
        }
    }, [activeSpreadsheetData, activeReportId]);

    // Efeito para monitorar alterações e atualizar isDirty
    useEffect(() => {
        const current = getSnapshot();
        // Se temos um relatório ativo, comparamos com o último salvo
        if (activeReportId && lastSavedData.current) {
            setIsDirty(current !== lastSavedData.current);
        } else {
            // Se for planilha nova, consideramos dirty se houver conteúdo
            setIsDirty(manualRows.length > 0 || reportTitle !== 'Relatório Financeiro');
        }
    }, [manualRows, columns, reportTitle, reportLogo, signatures, getSnapshot, activeReportId]);

    const generateRankingFromData = useCallback((data: MatchResult[], reportName: string) => {
        setIsRankingLoading(true);
        setManualRows([]);
        setTimeout(() => {
            try {
                const { rows, columns: cols, title } = rankingService.generateRanking(data, churches, reportName);
                setColumns(cols);
                setManualRows(rows);
                setReportTitle(title);
                setActiveTemplate('ranking');
                if (rows.length === 0) showToast("Relatório vazio ou sem dados para ranking.", "error");
            } catch (error) {
                showToast("Erro ao processar dados para o ranking.", "error");
            } finally { setIsRankingLoading(false); }
        }, 50); 
    }, [churches, showToast]);

    const handleRankingClick = () => {
        if (matchResults.length > 0) {
            generateRankingFromData(matchResults, activeReportId ? '' : 'Sessão Atual');
        } else {
            setShowReportSelector(true);
        }
    };

    const handleManualClick = () => {
        if (activeReportId) setActiveReportId(null);
        setActiveTemplate('manual_structure');
        setManualRows([]);
        setReportTitle("Relatório Manual");
        setColumns(analysisProcessor.createDefaultColumns());
        lastSavedData.current = ''; 
        setIsDirty(false);
        showToast("Nova planilha criada.", "success");
    };

    const handleSelectReport = async (report: any) => {
        setShowReportSelector(false);
        setIsLoading(true);
        try {
            let results = report.data?.results;
            let spreadsheet = report.data?.spreadsheet;

            if (!results && !spreadsheet) {
                const { data } = await supabase.from('saved_reports').select('data').eq('id', report.id).single();
                const parsedData = typeof data?.data === 'string' ? JSON.parse(data.data) : data?.data;
                results = parsedData?.results;
                spreadsheet = parsedData?.spreadsheet;
            }

            if (results?.length > 0 || spreadsheet) {
                setActiveReportId(report.id);
                setHasActiveSession(true);

                if (results?.length > 0) {
                    const hydrated = results.map((r: any) => ({ 
                        ...r, 
                        church: churches.find((c: any) => c.id === (r.church?.id || r._churchId)) || r.church || PLACEHOLDER_CHURCH 
                    }));
                    setMatchResults(hydrated);
                    setReportPreviewData({
                        income: groupResultsByChurch(hydrated.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                        expenses: { 'all_expenses_group': hydrated.filter((r: any) => r.transaction.amount < 0) }
                    });

                    if (!spreadsheet) {
                        generateRankingFromData(hydrated, report.name);
                    }
                }

                showToast(`Relatório "${report.name}" carregado.`, "success");
            } else { 
                showToast("Relatório vazio.", "error"); 
            }
        } catch (error: any) { 
            showToast("Erro ao processar relatório.", "error"); 
        } finally { setIsLoading(false); }
    };

    const handleLogoUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => setReportLogo(e.target?.result as string);
            reader.readAsDataURL(file);
        }
    };

    const handleSave = () => {
        const data: SpreadsheetData = { title: reportTitle, logo: reportLogo, columns, rows: manualRows, signatures };
        if (activeReportId) {
            if (!isDirty) return;

            overwriteSavedReport(activeReportId, [], data);
            lastSavedData.current = getSnapshot(); 
            setIsDirty(false);
        } else {
            openSaveReportModal({ type: 'spreadsheet', groupName: reportTitle, spreadsheetData: data, results: [] });
        }
    };

    const sortedRows = useMemo(() => analysisProcessor.sortRows(manualRows, sortConfig), [manualRows, sortConfig]);
    const summaryData = useMemo(() => analysisProcessor.calculateSummary(manualRows), [manualRows]);

    return {
        activeTemplate, setActiveTemplate, reportTitle, setReportTitle, reportLogo, signatures, setSignatures,
        manualRows, setManualRows, isRankingLoading, columns, setColumns, sortConfig, setSortConfig,
        sumModal, setSumModal, sumValue, setSumValue, showReportSelector, setShowReportSelector,
        fileInputRef, handleRankingClick, handleManualClick, handleSelectReport, handleLogoUpload,
        handleSave, sortedRows, summaryData, savedReports, activeReportId, isDirty
    };
};
